package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsLineBreak() throws Exception {
        // Given
        char lineBreakChar = '\n'; // Assuming LF is the line break character
        Character lineBreakCharacter = Character.valueOf(lineBreakChar);

        // When
        boolean result = invokePrivateStaticMethod(CSVFormat.class, "isLineBreak", lineBreakCharacter);

        // Then
        assertTrue(result);
    }

    private static boolean invokePrivateStaticMethod(Class<?> clazz, String methodName, Object... args) throws Exception {
        Method method = clazz.getDeclaredMethod(methodName, Character.class);
        method.setAccessible(true);
        return (boolean) method.invoke(null, (Character) args[0]);
    }
}
